mapper.insert:
INSERT  INTO TB_SYS_LOG
      ( REQUST_ID
      , SVC_NM
      , METHOD_NM
      , PROCESS_SE_CODE
      , PROCESS_TIME
      , RQESTER_ID
      , RQESTER_IP
      , OCCRRNC_DE )
VALUES  ( #{requstId}
        , #{srvcNm}
        , #{methodNm}
        , #{processSeCode}
        , #{processTime}
        , #{rqesterId}
        , #{rqesterIp}
        , to_char(NOW(), 'YYYYMMDD') )

mapper.select:
SELECT A.REQUST_ID , A.OCCRRNC_DE , A.SVC_NM , A.METHOD_NM , A.PROCESS_SE_CODE , C.CODE_NM AS PROCESS_SE_CODE_NM , A.PROCESS_TIME , A.RQESTER_IP , A.RQESTER_ID , B.USER_NM AS RQESTER_NM FROM TB_SYS_LOG A LEFT OUTER JOIN VW_USER_MASTER B ON A.RQESTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.PROCESS_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM033'
AND C.CODE_NM LIKE '%' || #{searchWrd} || '%'
AND A.OCCRRNC_DE BETWEEN #{searchBgnDe} AND #{searchEndDe}
ORDER BY A.OCCRRNC_DE DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(A.REQUST_ID) AS cnt FROM TB_SYS_LOG A LEFT OUTER JOIN VW_USER_MASTER B ON A.RQESTER_ID = B.ESNTL_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE C ON A.PROCESS_SE_CODE = C.CODE WHERE C.CODE_ID = 'COM033'
AND C.CODE_NM LIKE '%' || #{searchWrd} || '%'
AND A.OCCRRNC_DE BETWEEN #{searchBgnDe} AND #{searchEndDe}
